By Frank V8.7.4&lt;hr&gt;&lt;div class=&quot;a--b&quot;&gt;&lt;h2 class=&quot;di-title cdo-section-title-hw hw&quot;&gt;Labels &amp; Codes&lt;/h2&gt;&lt;h4&gt;List of Codes&lt;/h4&gt;&lt;a name=&quot;_top&quot;&gt; &lt;/a&gt;&lt;ul&gt;&lt;li&gt;&lt;a class=&quot;query&quot; style=&quot;text-decoration:none&quot; href=&quot;#adjectives&quot;&gt;Adjectives&lt;/a&gt;&lt;/li&gt;&lt;li&gt;&lt;a class=&quot;query&quot; style=&quot;text-decoration:none&quot; href=&quot;#nouns&quot;&gt;Nouns&lt;/a&gt;&lt;/li&gt;&lt;li&gt;&lt;a class=&quot;query&quot; style=&quot;text-decoration:none&quot; href=&quot;#verbs&quot;&gt;Verbs&lt;/a&gt;&lt;/li&gt;&lt;li&gt;&lt;a class=&quot;query&quot; style=&quot;text-decoration:none&quot; href=&quot;#other&quot;&gt;Other labels&lt;/a&gt;&lt;/li&gt;&lt;/ul&gt;&lt;span id=&quot;adjectives&quot;&gt;&lt;/span&gt;&lt;a style=&quot;text-decoration:none&quot; class=&quot;hw_subnumb&quot; href=&quot;entry://#_top&quot;&gt;Adjectives &lt;/a&gt;&lt;table style=&quot;border:0; border-collapse: collapse; border-spacing: 0; width: 100%; padding: 5px&quot;&gt;&lt;tbody&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;adjective&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word that describes a noun or pronoun&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[after noun]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;An adjective that only follows a noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[after verb]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;An adjective that only follows a verb.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[before noun]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;An adjective that only goes before a noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;comparative&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The form of an adjective or adverb that expresses a difference in amount, number, degree, or quality.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;superlative&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The form of an adjective or adverb that expresses that the thing or person being described has more of the particular quality than anything or anyone else of the same type.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[not gradable]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;An adjective that has no comparative or superlative form.&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;span id=&quot;nouns&quot;&gt;&lt;/span&gt;&lt;a style=&quot;text-decoration:none&quot; class=&quot;hw_subnumb&quot; href=&quot;entry://#_top&quot;&gt;Nouns &lt;/a&gt;&lt;table style=&quot;border:0; border-collapse: collapse; border-spacing: 0; width: 100%; padding: 5px&quot;&gt;&lt;tbody&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot;&gt;&lt;i&gt;noun&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word that refers to a person, place or thing.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot; class=&quot;def-grammar&quot;&gt;[C]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;Countable noun: a noun that has a plural.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot; class=&quot;def-grammar&quot;&gt;[U]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;Uncountable or singular noun: a noun that has no plural.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot; class=&quot;def-grammar&quot;&gt;[S]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A singular noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot;&gt;&lt;i&gt;plural&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The plural form of a noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot;&gt;&lt;i&gt;noun&lt;/i&gt;&amp;nbsp;[plural]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A noun that can only be used in the plural.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot; class=&quot;def-grammar&quot;&gt;[usually plural]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A noun usually used in the plural.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot; class=&quot;def-grammar&quot;&gt;[usually singular]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A countable noun usually used in the singular.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; valign=&quot;top&quot; class=&quot;def-grammar&quot;&gt;[+ sing/pl verb]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A noun that refers to a group of people acting collectively. When used in the singular it can be followed by either a singular or a plural verb in British English. In American English a singular verb is preferred.&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;span id=&quot;verbs&quot;&gt;&lt;/span&gt;&lt;a style=&quot;text-decoration:none&quot; class=&quot;hw_subnumb&quot; href=&quot;entry://#_top&quot;&gt;Verbs &lt;/a&gt;&lt;table style=&quot;border:0; border-collapse: collapse; border-spacing: 0; padding: 5px; width:100%;&quot;&gt;&lt;tbody&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;verb&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word that describes an action, state or experience.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[T]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;Transitive verb: a verb that has an object.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[I]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;Intransitive verb: a verb that has no object.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;auxiliary verb&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The verbs &lt;font color=&quot;BLUE&quot;&gt;be&lt;/font&gt;, &lt;font color=&quot;BLUE&quot;&gt;have&lt;/font&gt; and &lt;font color=&quot;BLUE&quot;&gt;do&lt;/font&gt;, which combine with other verbs to make different forms like &lt;i&gt;passives&lt;/i&gt;, &lt;i&gt;questions&lt;/i&gt; and the &lt;i&gt;continuous&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;modal verb&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;Verbs, such as &lt;font color=&quot;BLUE&quot;&gt;must&lt;/font&gt; and &lt;font color=&quot;BLUE&quot;&gt;can&lt;/font&gt;, that add meaning such as &lt;i&gt;certainty&lt;/i&gt; and &lt;i&gt;obligation&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;past simple&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The past simple form of the verb (eat &lt;font color=&quot;BLUE&quot;&gt;ate&lt;/font&gt; eaten).&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;past participle&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The past participle of the verb (eat ate &lt;font color=&quot;BLUE&quot;&gt;eaten&lt;/font&gt;).&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;present simple&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;The present participle of the verb (&lt;font color=&quot;BLUE&quot;&gt;tying&lt;/font&gt; tied).&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot;&gt;&lt;i&gt;phrasal verb&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed by an adverb or a preposition.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[L]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;Linking verb: an intransitive verb that is followed by a noun or adjective that refers back to the subject of the sentence.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[L only + adjective]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A linking verb only followed by an adjective.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[L only + noun]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A linking verb only followed by a noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ adv/prep]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb that must be followed by an adverb or preposition.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ &lt;i&gt;that&lt;/i&gt; clause]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed by a clause beginning with &lt;i&gt;that&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ question word]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed by a question word.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ speech]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb used with direct speech.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ &lt;i&gt;to&lt;/i&gt; infinitive]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed by the infinitive with &lt;i&gt;to&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ infinitive without &lt;i&gt;to&lt;/i&gt;]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed by the infinitive without &lt;i&gt;to&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ -&lt;i&gt;ing&lt;/i&gt;] verb&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed by the -ing form of the verb.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ &lt;i&gt;not&lt;/i&gt; or &lt;i&gt;so&lt;/i&gt;]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb followed immediately by &lt;i&gt;not&lt;/i&gt; or &lt;i&gt;so&lt;/i&gt; where these replace a clause.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ two objects]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb that has a direct and indirect object.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + adjective]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by an adjective.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + noun]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by a noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + noun or adjective]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by a noun or adjective.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + &lt;i&gt;as&lt;/i&gt; noun or adjective]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by &lt;i&gt;as&lt;/i&gt; and a noun or an adjective.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + &lt;i&gt;to be&lt;/i&gt; noun or adjective]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by &lt;i&gt;to be&lt;/i&gt; and a noun or an adjective.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + &lt;i&gt;that&lt;/i&gt; clause]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by a &lt;i&gt;that&lt;/i&gt; clause.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + &lt;i&gt;to&lt;/i&gt; infinitive]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by an infinitive with &lt;i&gt;to&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + infinitive without &lt;i&gt;to&lt;/i&gt;]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by an infinitive without &lt;i&gt;to&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + past participle]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by a past participle.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + &lt;i&gt;ing&lt;/i&gt; verb]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by the &lt;i&gt;-ing&lt;/i&gt; form of a verb.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ obj + question word]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb with an object followed by a question word.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[usually passive]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb usually used in the passive.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td valign=&quot;top&quot; width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[not continuous]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A verb not used in the continuous form.&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;span id=&quot;other&quot;&gt;&lt;/span&gt;&lt;a style=&quot;text-decoration:none&quot; class=&quot;hw_subnumb&quot; href=&quot;entry://#_top&quot;&gt;Other labels &lt;/a&gt;&lt;table style=&quot;border:0; border-collapse: collapse; border-spacing: 0; width: 100%; padding: 5px&quot;&gt;&lt;tbody&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;adverb&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word that gives information about a verb, adjective, another adverb, or a sentence.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;conjunction&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word such as &lt;font color=&quot;BLUE&quot;&gt;and&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt;although&lt;/font&gt; used to link two parts of a sentence.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;determiner&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word such as &lt;font color=&quot;BLUE&quot;&gt;the&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt;this&lt;/font&gt; used before a noun to show which particular example of a noun is being referred to.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;number&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word that refers to a number.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;ordinal number&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A number such as 1st, 2nd, 3rd, 4th, that shows the position of something in a list of things.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;preposition&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word that is used before a noun, a noun phrase, or a pronoun, connecting it to another word.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;predeterminer&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word such as &lt;font color=&quot;BLUE&quot;&gt;both&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt;all&lt;/font&gt; used before other determiners.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;pronoun&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word such as &lt;font color=&quot;BLUE&quot;&gt;it&lt;/font&gt;, or &lt;font color=&quot;BLUE&quot;&gt;mine&lt;/font&gt; used to replace a noun.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;prefix&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A letter or group of letters such as &lt;font color=&quot;BLUE&quot;&gt;un-&lt;/font&gt;, &lt;font color=&quot;BLUE&quot;&gt;pre-&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt;anti-&lt;/font&gt; added to the beginning of a word to make a new word.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;suffix&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A letter or group of letters such as &lt;font color=&quot;BLUE&quot;&gt;-less&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt; -ment&lt;/font&gt; added to the end of a word to make a new word.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot;&gt;&lt;i&gt;exclamation&lt;/i&gt;&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word or expression such as &lt;font color=&quot;BLUE&quot;&gt;damn!&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt;oh dear!&lt;/font&gt; used to express strong feelings.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ &lt;i&gt;ing&lt;/i&gt; verb]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word or phrase followed by the &lt;i&gt;-ing&lt;/i&gt; form of the verb.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ &lt;i&gt;to&lt;/i&gt; infinitive]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word or phrase followed by the infinitive with to.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ &lt;i&gt;that&lt;/i&gt;]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word or phrase followed by a clause beginning with &lt;i&gt;that&lt;/i&gt;.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[+ question word]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word or phrase followed by a question word.&lt;/td&gt;&lt;/tr&gt;&lt;tr bgcolor=&quot;#CCCCCC&quot;&gt;&lt;td width=&quot;25%&quot; class=&quot;def-grammar&quot;&gt;[as form of address]&lt;/td&gt;&lt;td width=&quot;75%&quot;&gt;A word or phrase such as &lt;font color=&quot;BLUE&quot;&gt;Mr&lt;/font&gt; or &lt;font color=&quot;BLUE&quot;&gt;dear&lt;/font&gt; used to address someone.&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/div&gt;

